{
  "mode": "io",
  "tests": [
    {
      "name": "valid_login",
      "input": "{\"username\": \"validUser\", \"password\": \"validPass\"}",
      "output": "{\"status\": \"success\", \"message\": \"Login successful\"}",
      "notes": "Tests a valid login scenario."
    },
    {
      "name": "invalid_login",
      "input": "{\"username\": \"invalidUser\", \"password\": \"invalidPass\"}",
      "output": "{\"status\": \"error\", \"message\": \"Invalid credentials\"}",
      "notes": "Tests an invalid login scenario."
    },
    {
      "name": "empty_username",
      "input": "{\"username\": \"\", \"password\": \"validPass\"}",
      "output": "{\"status\": \"error\", \"message\": \"Username cannot be empty\"}",
      "notes": "Tests edge case of empty username."
    },
    {
      "name": "empty_password",
      "input": "{\"username\": \"validUser\", \"password\": \"\"}",
      "output": "{\"status\": \"error\", \"message\": \"Password cannot be empty\"}",
      "notes": "Tests edge case of empty password."
    },
    {
      "name": "long_username",
      "input": "{\"username\": \"" + "a".repeat(256) + "\", \"password\": \"validPass\"}",
      "output": "{\"status\": \"error\", \"message\": \"Username too long\"}",
      "notes": "Tests edge case of username exceeding length limit."
    },
    {
      "name": "long_password",
      "input": "{\"username\": \"validUser\", \"password\": \"" + "b".repeat(256) + "\"}",
      "output": "{\"status\": \"error\", \"message\": \"Password too long\"}",
      "notes": "Tests edge case of password exceeding length limit."
    },
    {
      "name": "successful_logout",
      "input": "{\"action\": \"logout\"}",
      "output": "{\"status\": \"success\", \"message\": \"Logout successful\"}",
      "notes": "Tests the logout functionality."
    },
    {
      "name": "unauthorized_access",
      "input": "{\"action\": \"accessProtectedResource\"}",
      "output": "{\"status\": \"error\", \"message\": \"Unauthorized access\"}",
      "notes": "Tests access to a protected resource without login."
    }
  ],
  "assumptions": "The API endpoints are correctly set up and accessible.",
  "notes": "Ensure that the application is running in the correct environment."
}
